#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
ملف مدمج - 1 بوت
تم الدمج تلقائياً من جميع ملفات .py
مع Flask - للاستضافات التي تسمح بـ Webserver
"""
import os, sys, threading, time, base64
import types
from flask import Flask, jsonify
from datetime import datetime

# Flask Application
app = Flask(__name__)

# متغير لحفظ حالة البوتات
bots_status = {}
start_time = None

